using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    string Summarize(string text);
}

public class DocumentSummarizer : IDocumentSummarizer
{
    private const int MaxSummarySentences = 3;

    public string Summarize(string text)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count == 0)
            return string.Empty;

        // Score each sentence by word count and position, then pick the top ones.
        var scored = sentences
            .Select((s, index) => new
            {
                Sentence = s,
                Score = ScoreSentence(s, index, sentences.Count)
            })
            .OrderByDescending(x => x.Score)
            .Take(MaxSummarySentences)
            .OrderBy(x => sentences.IndexOf(x.Sentence)) // preserve original order
            .Select(x => x.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end-of-string.
        var raw = System.Text.RegularExpressions.Regex
            .Split(text, @"(?<=[.!?])\s+");

        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static double ScoreSentence(string sentence, int index, int totalSentences)
    {
        int wordCount = sentence.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length;

        // Prefer longer sentences (more informative).
        double lengthScore = Math.Min(wordCount / 20.0, 1.0);

        // Boost first and second sentences (they often carry the main idea).
        double positionScore = index switch
        {
            0 => 1.0,
            1 => 0.8,
            _ => 0.5
        };

        return lengthScore + positionScore;
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var summary = _summarizer.Summarize(request.Text);

        return Ok(new SummarizeResponse { Summary = summary });
    }
}

